import math

def baby_step_giant_step(a, b, n):
    if n == 1:
        return 0

    if a % n == 0:
        if b % n == 0:
            return 1 if n > 1 else 0
        else:
            return None

    if a % n == 1:
        if b % n == 1:
            return 0
        else:
            return None

    m = math.ceil(math.sqrt(n))

    baby_steps = {}
    current_val = 1
    for j in range(m):
        if current_val == b % n: # Check if b is found in baby steps (x < m)
            return j
        baby_steps[current_val] = j
        current_val = (current_val * a) % n

    try:
        a_m = pow(a, m, n)
        a_inv_m = pow(a_m, -1, n)
    except ValueError:
        return None

    current_giant_step_val = b
    for k in range(m):
        if current_giant_step_val in baby_steps:
            j = baby_steps[current_giant_step_val]
            return j + k * m
        current_giant_step_val = (current_giant_step_val * a_inv_m) % n

    return None
